        s += chunk
    }

    // Step 2: Identify and count all valid words
    // Use a map to store word frequencies
    wordCounts := Map<string, Int64>()
    n := len(s)
    i := 0

    for i < n {
        // Skip separators
        if !isWordChar(s[i]) {
            i++
            continue
        }

        // Found the start of a potential word
        start := i
        j := i

        // Find the end of the maximal contiguous sequence of word characters
        for j < n && isWordChar(s[j]) {
            j++
        }

        // Extract the raw segment
        rawWord := s[start:j]

        // Validate the raw segment
        if isValidWord(rawWord) {
            // If valid, count it
            wordCounts[rawWord]++
        }

        // Move pointer i past the segment just processed
        i = j
    }

    // Step 3: Count occurrences for each query
